(()=>{"use strict";const e=document.querySelectorAll(".target-num"),t=document.querySelectorAll(".symbol"),n=document.getElementById("start-make"),c=document.getElementById("strplus"),o=document.getElementById("parentheses"),l=document.getElementById("sort"),r=document.getElementById("answer");n.addEventListener("click",()=>{r.innerHTML="計算中...";const n=Array.from(e).map(e=>Number(e.value)),m=Array.from(t).map(e=>e.checked);if(console.log(n),console.log(m),n.some(e=>isNaN(e)))return void alert("整数を正しく入力してください");const s=(c.checked,o.checked,l.checked,["(1+2)*3+1","4*2+3-1"]);0===s.length&&s.push("[見つかりませんでした]");for(let e=0;e<s.length;e++){const t=document.createElement("p");t.textContent=s[e],t.className="answer-item",r.appendChild(t)}})})();